     result: *mut c_void,
     path: *const c_char,
 ) -> c_int {
-    type F = unsafe extern "C" fn(*mut c_void, *const c_char) -> c_int;
-    let sym = unsafe { libc::dlsym(libc::RTLD_NEXT, c"__file_change_detection_for_path".as_ptr()) };
